#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
ll a[N],dp[N],n,m,sum,dq[N],dp2[N],dqs=1,dqt,mid,stl[N],lcnt,str[N],rcnt;
void pushl(ll num)
{
	if(!lcnt||dp2[stl[lcnt]]>dp2[num]) stl[++lcnt]=num;
}
void pushr(ll num)
{
	if(!rcnt||dp2[str[rcnt]]>dp2[num]) str[++rcnt]=num;
}
void rebuild()
{
	mid=(dqs+dqt)/2;
	lcnt=rcnt=0;
	for(ll i=mid;i>=dqs;i--)
	{
		pushl(i);
	}
	for(ll i=mid+1;i<=dqt;i++)
	{
		pushr(i);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	for(ll i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	ll pos=1;
	for(ll i=1;i<=n;i++)
	{
		sum+=a[i];
		while(sum>m)
		{
			sum-=a[pos];
			pos++;
		}
//		cout<<i<<" "<<sum<<"\n";
		while(dqs<=dqt&&a[dq[dqt]]<=a[i])
		{
//			cout<<dqs<<" "<<dqt<<" aaa\n";
			if(lcnt&&stl[lcnt]==dqt)
			{
//				cout<<"lcnt : "<<lcnt<<" -> "<<lcnt-1<<"  bbb(lcnt--)\n";
				lcnt--;
			}
			if(rcnt&&str[rcnt]==dqt)
			{
//				cout<<"rcnt : "<<rcnt<<" -> "<<rcnt-1<<"  ccc(rcnt--)\n";
				rcnt--;
			}
			dqt--;
//			cout<<"dqt--(ddd)\n";
			if(dqt<=mid)
			{
//				cout<<"-----rebuild()\n";
				rebuild();
			}
		}
		dq[++dqt]=i;
		if(dqs==dqt)
		{
			dp2[dqt]=dp[pos-1]+a[i];
		}
		else dp2[dqt]=dp[dq[dqt-1]]+a[i];
		pushr(dqt);
		if(stl[lcnt]==dqs) lcnt--;
		if(str[rcnt]==dqs) rcnt--;
		while(dqs<=dqt&&dq[dqs]<pos)
		{
			if(lcnt&&stl[lcnt]==dqs) lcnt--;
			if(rcnt&&str[rcnt]==dqs) rcnt--;
			dqs++;
			if(dqs>mid)
			{
				rebuild();
			}
		}
		dp[i]=a[dq[dqs]]+dp[pos-1];
		if(lcnt) dp[i]=min(dp[i],dp2[stl[lcnt]]);
		if(rcnt) dp[i]=min(dp[i],dp2[str[rcnt]]);
	}
	cout<<dp[n];
	return 0;
}
